import React from "react";
import "./nav.css";

function Nav() {
  const [isActive, setIsActive] = React.useState(false);
  const handleClick = () => {
    setIsActive((current) => !current);
  };
  const displayChange = () => {
    const style = document.querySelectorAll(".pushMenu");
    if (style.display.isActive != "block") {
      style.display.isActive = "block";
    } else {
      style.display.isActive = "none";
    }
  };
  return (
    <div>
      <div
        value={isActive}
        className="pushMenu"
        onChange={(e) => displayChange(e.target.value)}
      ></div>
      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

export default Nav;

